var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>수심 15. 21. 30. 40. 55. 60. 65. 69…….</color>","JPN":"<color=#ff3636>水深15、21、30、40、55、60、65、69……</color>","ENG":"<color=#ff3636>Depth level 15. 21. 30. 40. 55. 60. 65. 69…</color>","TWN":"<color=#ff3636>水深15、21、30、40、55、60、65、69……</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>수압으로 인한 침수 가능성 존재. 대응 필요.</color>","JPN":"<color=#ff3636>水圧による浸水の可能性が浮上。対応が必要。</color>","ENG":"<color=#ff3636>Water pressure presents leakage risk. Urging immediate response.</color>","TWN":"<color=#ff3636>因為水壓的關係有進水的風險，需要應對。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>사고회로의 과부하 감지. 원인을 파악 중입니다.</color>","JPN":"<color=#ff3636>思考回路の過負荷感知。原因を把握中です。</color>","ENG":"<color=#ff3636>Reasoning system overload. Running diagnostics…</color>","TWN":"<color=#ff3636>思考迴路超載，正在調查原因。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>원인 불명. 사고회로 재기동. 재기동. 재기동.</color>","JPN":"<color=#ff3636>過負荷の原因、不明。思考回路再起動。再起動。再起動。</color>","ENG":"<color=#ff3636>Cause unknown. Reinitializing reasoning system. Reinitialize. Reinitialize.</color>","TWN":"<color=#ff3636>無法確認原因。重新啟動思考迴路。重新啟動。重新啟動。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"바닷속.","JPN":"海の中。","ENG":"The depths.","TWN":"海底"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"캄캄한 바닷속.","JPN":"真っ暗な海の中。","ENG":"The deep, dark depths of the ocean.","TWN":"漆黑的海底"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"잔여 동력은 2%. 이대로 밑바닥까지 가라앉아 버리면, 수압에 짓눌려 파괴될 수 있을까.","JPN":"残余エネルギーは2％。このまま底まで沈んでしまうと、水圧で破壊されるだろうか。","ENG":"Only 2% of power remains. Perhaps the water pressure of the seabed will crush and destroy the frame.","TWN":"剩餘動能2%。就這樣沉到海底的話，因為水壓而壞掉嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"시뮬레이션 결과. 불가능.","JPN":"シミュレーション結果は不可能。","ENG":"Simulation result… Impossible.","TWN":"模擬結果，無法。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"심해에 잠긴 채 지질학적 시간이 경과해도, 이 프레임은 그대로 남아 있을 것이다.","JPN":"深海に沈んだまま地質学的時間が経過しても、このフレームはそのまま残るだろう。","ENG":"No matter how deep this frame sinks into the abyss… it will remain intact.","TWN":"在深海中沉睡的狀態下，就算經過地質時間，這副軀殼也會存留下來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"근거는 있다.","JPN":"根拠はある。","ENG":"There is evidence to back this analysis.","TWN":"是有根據的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"……파괴할 방법을 찾기 전까지 누군가 맡고 있어야 한다고, 엠버 소장이 말했으니까.","JPN":"……破壊する方法を見つけるまで誰かが引き受けていなければならないと、アンバー所長が言ったから。","ENG":"Director Ember said someone must look after this frame until a way can be found to destroy it.","TWN":"……在找到破壞的方法前，必須先交給某個人。這是琥珀所長說的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 현재, 허가되지 않은 콜드 케이스 반출이 확인되었습니다.</color>","JPN":"<color=#ffd34c>ご案内いたします。現在、許可されていないコールドケースの持ち出しが確認されました。</color>","ENG":"<color=#ffd34c>Attention. Unauthorized release of Cold Case has been confirmed.</color>","TWN":"<color=#ffd34c>通知，確認到Cold Case未經許可移出。</color>"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>콜드 케이스의 확보를 위해 보안팀을 급파한 상황입니다. 시설 내의 모든 관계자들은 상황 종료 전까지 이동을 자제하여 주십시오.</color>","JPN":"<color=#ffd34c>コールドケースの確保のためセキュリティチームを急ぎ派遣しています。\\n施設内のすべての関係者は、状況終了まで移動を控えてください。</color>","ENG":"<color=#ffd34c>A security team has been dispatched to secure the Cold Case. All personnel in the facility are advised to remain in place until the situation is clear.</color>","TWN":"<color=#ffd34c>安全組已緊急出動尋找Cold Case。情況結束前，設施內所有人員請勿移動。</color>"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"좋아. 커넥터는 잘 맞네.","JPN":"よし。コネクターはちゃんと合ってる。","ENG":"Good. At least the connector fits.","TWN":"很好，連接器剛剛好。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"냉각기 효율이 예상치를 밑도는 게 불안한데. 르네 교수한테 부탁했어야 하나.","JPN":"冷却器の効率が予想値を下回るのが不安だな。ルネ教授に頼むべきだったか。","ENG":"I'm still nervous about the coolers under-performing. Maybe I should have asked Professor Renée for help.","TWN":"冷卻裝置效能比預期的還低，有點不安呢。果然還是應該要拜託洛奈教授才對嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"자, 움직여 봐. 호라이즌. 센서에 익숙해지려면 시간은 조금 걸리겠지만.","JPN":"さあ、動いてみな、ホライズン。センサーに慣れるまで時間が少しかかると思うけど。","ENG":"Now, try moving, Horizon. Mind you, it will take some time till you get accustomed to the sensors.","TWN":"來，地平線你動動看。雖然要熟悉感應器會需要花些時間。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"미쳤습니까, 엠버?","JPN":"正気ですか、アンバー？","ENG":"Have you lost your mind, Ember?","TWN":"琥珀，你腦袋不正常嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"잘못 짚었어. 나는 누구보다 차갑고 이성적으로 행동하고 있으니까.","JPN":"もちろんよ。私は誰よりも冷静かつ理性的に行動している。","ENG":"Not one bit. There's no one more objective and rational than me right now.","TWN":"答錯，是因為我比任何人都還要沉著理性。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};